mapper.select:
SELECT c.comment_id AS commentId, c.article_id AS articleId, a.title AS title, c.content, c.user, c.state, c.create_at AS createAt FROM comment c JOIN articles a ON c.article_id = a.article_id
AND c.article_id = #{articleId}
AND a.title LIKE concat('%', #{title}, '%')
AND c.content LIKE concat('%', #{content}, '%')
AND c.state = #{state}
ORDER BY c.create_at DESC
